"""matplotlib.scale — axis scale classes."""

import numpy as _np


class ScaleBase:
    name = None
    def __init__(self, axis=None, **kwargs): pass
    def get_transform(self): return None
    def set_default_locators_and_formatters(self, axis): pass
    def limit_range_for_scale(self, vmin, vmax, minpos): return (vmin, vmax)


class LinearScale(ScaleBase):
    name = 'linear'


class LogScale(ScaleBase):
    name = 'log'
    def __init__(self, axis=None, *, base=10, subs=None, nonpositive='clip'):
        self.base = base
        self.subs = subs
        self.nonpositive = nonpositive


class SymmetricalLogScale(ScaleBase):
    name = 'symlog'
    def __init__(self, axis=None, *, base=10, linthresh=2, subs=None, linscale=1):
        self.base = base
        self.linthresh = linthresh
        self.subs = subs
        self.linscale = linscale


class LogitScale(ScaleBase):
    name = 'logit'
    def __init__(self, axis=None, *, nonpositive='mask', one_half='\\frac{1}{2}',
                 use_overline=False):
        self.nonpositive = nonpositive


class FuncScale(ScaleBase):
    name = 'function'
    def __init__(self, axis, functions):
        self._forward, self._inverse = functions


class AsinhScale(ScaleBase):
    name = 'asinh'
    def __init__(self, axis=None, *, linear_width=1.0, base=10, subs='auto', **kwargs):
        self.linear_width = linear_width


# Scale registry
_scale_mapping = {
    'linear': LinearScale,
    'log': LogScale,
    'symlog': SymmetricalLogScale,
    'logit': LogitScale,
    'function': FuncScale,
    'asinh': AsinhScale,
}


def scale_factory(scale, axis, **kwargs):
    if scale in _scale_mapping:
        return _scale_mapping[scale](axis, **kwargs)
    raise ValueError(f"Unknown scale: {scale!r}")


def get_scale_names():
    return list(_scale_mapping.keys())


def register_scale(scale_class):
    _scale_mapping[scale_class.name] = scale_class
